<?php function isNumber($s){$seenDigit=false;$seenDot=false;$seenExp=false;$digitAfterExp=true;for($i=0;$i<strlen($s);$i++){$ch=$s[$i];if($ch>='0'&&$ch<='9'){$seenDigit=true;if($seenExp)$digitAfterExp=true;}elseif($ch=='+'||$ch=='-'){if($i!=0&&$s[$i-1]!='e'&&$s[$i-1]!='E')return false;}elseif($ch=='.'){if($seenDot||$seenExp)return false;$seenDot=true;}elseif($ch=='e'||$ch=='E'){if($seenExp||!$seenDigit)return false;$seenExp=true;$digitAfterExp=false;}else return false;}return $seenDigit&&$digitAfterExp;} $lines=file('php://stdin', FILE_IGNORE_NEW_LINES); if($lines){$t=intval(trim($lines[0]));$out=[];for($i=0;$i<$t;$i++)$out[]=isNumber($lines[$i+1])?'true':'false';echo implode("\n",$out);} ?>
